import{_ as a,o as t,c as o,S as r}from"./chunks/framework.DZlzLDBr.js";const m=JSON.parse('{"title":"Image Occlusion","description":"","frontmatter":{},"headers":[],"relativePath":"Image-Occlusion.md","filePath":"Image-Occlusion.md","lastUpdated":null}'),n={name:"Image-Occlusion.md"};function s(i,e,d,l,h,c){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="image-occlusion" tabindex="-1">Image Occlusion <a class="header-anchor" href="#image-occlusion" aria-label="Permalink to &quot;Image Occlusion&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>Image Occlusion (IO) hides parts of an image so you recall the hidden label or structure during review.</p><h2 id="creating-an-io-card" tabindex="-1">Creating an IO card <a class="header-anchor" href="#creating-an-io-card" aria-label="Permalink to &quot;Creating an IO card&quot;">​</a></h2><h3 id="using-the-modal-recommended" tabindex="-1">Using the modal (recommended) <a class="header-anchor" href="#using-the-modal-recommended" aria-label="Permalink to &quot;Using the modal (recommended)&quot;">​</a></h3><ol><li>Right-click in a note → <strong>Add flashcard → Image Occlusion Card</strong>.</li><li>Choose an image from your vault or drag one into the modal.</li><li>The <strong>IO Editor</strong> opens with the image on a canvas.</li><li>Use the toolbar to draw mask regions over the areas you want to test.</li><li>Choose a save mode (Solo or All) and click <strong>Save</strong>.</li></ol><h3 id="writing-in-markdown" tabindex="-1">Writing in Markdown <a class="header-anchor" href="#writing-in-markdown" aria-label="Permalink to &quot;Writing in Markdown&quot;">​</a></h3><p>Add a card block with an <code>IO</code> field pointing to an image:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | Anatomy — Bones of the hand |</span></span>
<span class="line"><span>IO | ![hand_diagram.png](./hand_diagram.png.md) |</span></span>
<span class="line"><span>G | Anatomy |</span></span></code></pre></div><p>After sync, open the IO Editor from review or the Card Browser to add masks.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The IO Editor is desktop-only. On mobile, a notice is shown.</p></div><h2 id="io-editor" tabindex="-1">IO Editor <a class="header-anchor" href="#io-editor" aria-label="Permalink to &quot;IO Editor&quot;">​</a></h2><p>The editor opens in a modal canvas.</p><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><strong>Occlusion</strong></td><td>Draw new mask rectangles/circles over the image</td></tr><tr><td><strong>Transform</strong></td><td>Move or resize existing masks</td></tr><tr><td><strong>Delete</strong></td><td>Remove the selected mask</td></tr><tr><td><strong>Reset</strong></td><td>Revert all masks to their saved state</td></tr></tbody></table><h3 id="shapes" tabindex="-1">Shapes <a class="header-anchor" href="#shapes" aria-label="Permalink to &quot;Shapes&quot;">​</a></h3><p>Masks can be rectangles or circles.</p><h3 id="zoom-pan" tabindex="-1">Zoom &amp; pan <a class="header-anchor" href="#zoom-pan" aria-label="Permalink to &quot;Zoom &amp; pan&quot;">​</a></h3><p>Use <strong>Zoom In</strong>, <strong>Zoom Out</strong>, and <strong>Fit</strong> to navigate large images. Hold <strong>Spacebar</strong> and drag to pan across the image.</p><h2 id="groups-mask-groups" tabindex="-1">Groups (mask groups) <a class="header-anchor" href="#groups-mask-groups" aria-label="Permalink to &quot;Groups (mask groups)&quot;">​</a></h2><p>Each mask has a <strong>group key</strong>. Masks with the same group key are revealed together during review.</p><ul><li>Type a key in the <strong>group input</strong> to assign the selected mask to a group.</li><li>Masks without a group key are treated as individual items.</li><li>During review, grouped masks are hidden/revealed as a unit.</li></ul><h3 id="hide-all-hide-one-group-mode" tabindex="-1">Hide all / Hide one / Group mode <a class="header-anchor" href="#hide-all-hide-one-group-mode" aria-label="Permalink to &quot;Hide all / Hide one / Group mode&quot;">​</a></h3><p>When creating IO cards in the modal, you can choose how masks behave:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Hide All</strong></td><td>All masks are hidden at once — you recall everything</td></tr><tr><td><strong>Hide One</strong></td><td>Only one mask (or group) is hidden per card — others remain visible</td></tr><tr><td><strong>Group</strong></td><td>Masks are grouped — each group becomes one review card</td></tr></tbody></table><h2 id="save-modes" tabindex="-1">Save modes <a class="header-anchor" href="#save-modes" aria-label="Permalink to &quot;Save modes&quot;">​</a></h2><p>When saving from the editor, choose one of two modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Button</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Solo</strong></td><td>Save Solo</td><td>Each mask (or group) becomes its own review card — only that region is hidden</td></tr><tr><td><strong>All</strong></td><td>Save All</td><td>All masks are hidden at once and revealed together</td></tr></tbody></table><h2 id="reveal-settings" tabindex="-1">Reveal settings <a class="header-anchor" href="#reveal-settings" aria-label="Permalink to &quot;Reveal settings&quot;">​</a></h2><p>In <strong>Settings → Cards</strong>, you can configure how IO cards are revealed during review:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Options</th><th>Description</th></tr></thead><tbody><tr><td><strong>Reveal mode</strong></td><td>Reveal All / Reveal Group / Reveal One</td><td>Controls how many masks are shown when you reveal the answer</td></tr></tbody></table><ul><li><strong>Reveal All</strong> — All masks are removed at once.</li><li><strong>Reveal Group</strong> — Only masks in the same group are revealed.</li><li><strong>Reveal One</strong> — Only the target mask is revealed.</li></ul><h2 id="how-cards-are-generated" tabindex="-1">How cards are generated <a class="header-anchor" href="#how-cards-are-generated" aria-label="Permalink to &quot;How cards are generated&quot;">​</a></h2><ul><li>The original <code>IO</code> card block becomes a <strong>parent</strong> card (not reviewable itself).</li><li>Sprout generates one <strong>child</strong> card per mask or group (depending on save mode).</li><li>Children inherit the parent&#39;s title and info fields.</li></ul><h2 id="review" tabindex="-1">Review <a class="header-anchor" href="#review" aria-label="Permalink to &quot;Review&quot;">​</a></h2><p>During review the image is displayed with coloured mask overlays. After revealing, the masks are removed so you can check your recall.</p><ul><li>Click the image to <strong>zoom</strong> into a full-screen overlay.</li><li>If the source image is missing, an error is shown and the card cannot render correctly.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Default IO attachment folder</td><td><code>Attachments/Image Occlusion/</code></td><td>Where IO images are stored</td></tr><tr><td>Delete orphaned IO images</td><td>On</td><td>Auto-delete images when their IO cards are removed</td></tr></tbody></table><p>Configure these in <strong>Settings → Storage → Image Occlusion</strong>.</p>`,41)])])}const u=a(n,[["render",s]]);export{m as __pageData,u as default};
